mapper.select:
SELECT a.* FROM announcement a


        AND a.status = #{status}


        AND a.category = #{category}


        AND a.region = #{region}


        AND a.source_id = #{sourceId}


        AND a.id IN (
            SELECT jp.announcement_id FROM job_position jp
            WHERE jp.education = #{education}
        )


        AND (
            a.title LIKE CONCAT('%', #{keyword}, '%')
            OR a.content_text LIKE CONCAT('%', #{keyword}, '%')
            OR a.recruit_unit LIKE CONCAT('%', #{keyword}, '%')
        )


ORDER BY a.publish_date DESC

    LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM announcement a


        AND a.status = #{status}


        AND a.category = #{category}


        AND a.region = #{region}


        AND (
            a.title LIKE CONCAT('%', #{keyword}, '%')
            OR a.content_text LIKE CONCAT('%', #{keyword}, '%')
            OR a.recruit_unit LIKE CONCAT('%', #{keyword}, '%')
        )
